    // markdown-it レンダリング
    document.addEventListener('DOMContentLoaded', function () {
      const el = document.querySelector('.markdown');
      if (!el) return;
      const md = window.markdownit({
        html: true,
        linkify: true,
        typographer: true,
        langPrefix: 'hljs language-'
      });
      md.use(window.markdownitEmoji);
      const _src = el.innerHTML
        .replace(/<p[^>]*>\s*/gi, '')
        .replace(/\s*<\/p>/gi, '\n\n');
      el.innerHTML = md.render(_src);
      el.querySelectorAll('pre code').forEach(function (block) { hljs.highlightElement(block); });
      twemoji.parse(el, { base: 'https://cdn.jsdelivr.net/gh/twitter/twemoji@v14.0.2/assets/' });
    });
    // テーマ切り替え (auto / light / dark)
    // localStorage 未設定時は OS 設定に追従、ボタン押下で light/dark を明示固定
    document.addEventListener('DOMContentLoaded', function () {
      const STORAGE_KEY = 'theme';
      const HLJS_BASE = 'https://cdn.jsdelivr.net/npm/@highlightjs/cdn-assets@11/styles/';
      const btn = document.querySelector('.theme-switch');
      const icon = btn.querySelector('i');
      const hlLink = document.querySelector('.js-hljs-theme');
      const lightMQL = window.matchMedia('(prefers-color-scheme: light)');

      const stored = () => {
        const v = localStorage.getItem(STORAGE_KEY);
        return v === 'light' || v === 'dark' ? v : null;
      };
      const resolved = () => stored() || (lightMQL.matches ? 'light' : 'dark');
      const render = () => {
        const t = resolved();
        document.documentElement.setAttribute('data-theme', t);
        icon.className = 'fas ' + (t === 'light' ? 'fa-sun' : 'fa-moon');
        if (hlLink) hlLink.href = HLJS_BASE + (t === 'light' ? 'github.min.css' : 'github-dark.min.css');
      };

      render();
      lightMQL.addEventListener('change', () => { if (!stored()) render(); });
      btn.addEventListener('click', () => {
        localStorage.setItem(STORAGE_KEY, resolved() === 'dark' ? 'light' : 'dark');
        render();
      });
    });
    // リンクカード (Microlink + localStorage キャッシュ + IntersectionObserver 遅延ロード)
    document.addEventListener('DOMContentLoaded', function () {
      var CACHE_PREFIX = 'ogp:';
      var CACHE_TTL = 7 * 24 * 60 * 60 * 1000;
      function getCached(url) {
        try {
          var raw = localStorage.getItem(CACHE_PREFIX + url);
          if (!raw) return null;
          var obj = JSON.parse(raw);
          if (Date.now() - obj.ts > CACHE_TTL) {
            localStorage.removeItem(CACHE_PREFIX + url);
            return null;
          }
          return obj.data;
        } catch (e) { return null; }
      }
      function setCached(url, data) {
        var payload = JSON.stringify({ ts: Date.now(), data: data });
        try {
          localStorage.setItem(CACHE_PREFIX + url, payload);
        } catch (e) {
          try {
            Object.keys(localStorage).forEach(function (k) {
              if (k.indexOf(CACHE_PREFIX) === 0) localStorage.removeItem(k);
            });
            localStorage.setItem(CACHE_PREFIX + url, payload);
          } catch (e2) {}
        }
      }
      function buildCard(href, d) {
        var card = document.createElement('a');
        card.className = 'link-card';
        card.href = href;
        card.target = '_blank';
        card.rel = 'noopener noreferrer';
        var div = document.createElement('div');
        var titleEl = document.createElement('strong');
        titleEl.textContent = d.title || href;
        div.appendChild(titleEl);
        if (d.description) {
          var desc = document.createElement('small');
          desc.textContent = d.description;
          div.appendChild(desc);
        }
        var metaEl = document.createElement('small');
        var logoUrl = d.logo && d.logo.url;
        if (logoUrl) {
          var fav = document.createElement('img');
          fav.src = logoUrl;
          fav.alt = '';
          fav.onerror = function () { this.style.display = 'none'; };
          metaEl.appendChild(fav);
        }
        try { metaEl.appendChild(document.createTextNode(new URL(href).hostname)); } catch (e) { metaEl.appendChild(document.createTextNode(href)); }
        div.appendChild(metaEl);
        card.appendChild(div);
        var imageUrl = d.image && d.image.url;
        if (imageUrl) {
          var img = document.createElement('img');
          img.src = imageUrl;
          img.alt = '';
          img.loading = 'lazy';
          card.appendChild(img);
        }
        return card;
      }
      function render(href, p, data) {
        var card = buildCard(href, data);
        p.parentNode.insertBefore(card, p.nextSibling);
      }
      function load(href, p) {
        var cached = getCached(href);
        if (cached) { render(href, p, cached); return; }
        fetch('https://api.microlink.io/?url=' + encodeURIComponent(href))
          .then(function (r) { return r.json(); })
          .then(function (json) {
            if (json.status !== 'success') return;
            setCached(href, json.data);
            render(href, p, json.data);
          })
          .catch(function () {});
      }
      var targets = [];
      document.querySelectorAll('.post-body a[href]').forEach(function (a) {
        var href = a.getAttribute('href');
        if (!href || !href.startsWith('http')) return;
        var p = a.closest('p');
        if (!p) return;
        targets.push({ a: a, href: href, p: p });
      });
      if ('IntersectionObserver' in window) {
        var io = new IntersectionObserver(function (entries) {
          entries.forEach(function (entry) {
            if (!entry.isIntersecting) return;
            var t = entry.target.__linkCardTarget;
            io.unobserve(entry.target);
            if (t) load(t.href, t.p);
          });
        }, { rootMargin: '1500px' });
        targets.forEach(function (t) {
          t.a.__linkCardTarget = t;
          io.observe(t.a);
        });
      } else {
        targets.forEach(function (t) { load(t.href, t.p); });
      }
    });
    // 目次生成
    document.addEventListener('DOMContentLoaded', function () {
      const body = document.querySelector('.post-body');
      if (!body) return;
      const headings = body.querySelectorAll('h2, h3, h4');
      const toc = document.querySelector('.content-toc > nav');
      if (!toc || !headings.length) return;
      const root = document.createElement('ul');
      const stack = [];
      headings.forEach(function (el, i) {
        const id = 'toc-' + i;
        if (!el.id) el.id = id;
        const level = parseInt(el.tagName[1]);
        const li = document.createElement('li');
        const a = document.createElement('a');
        a.href = '#' + id;
        a.textContent = el.textContent.trim();
        li.appendChild(a);
        while (stack.length && stack[stack.length - 1].level >= level) stack.pop();
        if (!stack.length) {
          root.appendChild(li);
        } else {
          let sub = stack[stack.length - 1].li.querySelector('ul');
          if (!sub) { sub = document.createElement('ul'); stack[stack.length - 1].li.appendChild(sub); }
          sub.appendChild(li);
        }
        stack.push({ level: level, li: li });
      });
      toc.appendChild(root);
    });
    // 目次スクロールハイライト
    document.addEventListener('DOMContentLoaded', function () {
      const toc = document.querySelector('.content-toc > nav');
      if (!toc) return;
      const links = toc.querySelectorAll('a');
      let lastActive = null;
      window.addEventListener('scroll', function () {
        let currentId = null;
        document.querySelectorAll('.post-body h2, .post-body h3, .post-body h4').forEach(function (h) {
          if (window.scrollY >= h.getBoundingClientRect().top + window.scrollY - 225) currentId = h.id;
        });
        links.forEach(function (a) {
          a.removeAttribute('aria-current');
          if (currentId && a.getAttribute('href') === '#' + currentId) {
            a.setAttribute('aria-current', 'true');
            if (lastActive !== a) {
              lastActive = a;
              toc.scrollTo({ top: a.offsetTop - toc.clientHeight / 2, behavior: 'smooth' });
            }
          }
        });
      });
    });
